import{_ as t,o as a,c as r,a1 as i}from"./chunks/framework.BwbI10pK.js";const h=JSON.parse('{"title":"Frameworks & Ecosystem","description":"","frontmatter":{},"headers":[],"relativePath":"en/frameworks/index.md","filePath":"en/frameworks/index.md"}'),n={name:"en/frameworks/index.md"};function o(s,e,d,l,c,u){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="frameworks-ecosystem" tabindex="-1">Frameworks &amp; Ecosystem <a class="header-anchor" href="#frameworks-ecosystem" aria-label="Permalink to &quot;Frameworks &amp; Ecosystem&quot;">​</a></h1><blockquote><p>Subtitle: See the engineering trade-offs behind React Fiber, Vue 3 reactivity, and state-management abstractions.</p></blockquote><h2 id="module-positioning" tabindex="-1">Module Positioning <a class="header-anchor" href="#module-positioning" aria-label="Permalink to &quot;Module Positioning&quot;">​</a></h2><p>Modern frontend frameworks abstract &quot;how to update the DOM&quot; more and more thoroughly, but abstraction is not free. React Fiber&#39;s interruptible chain rendering, Vue 3&#39;s Proxy reactivity, and Zustand&#39;s atomic state — each solution represents a different trade-off among scheduling, dependency tracking, performance, and developer experience.</p><p>This module does not just teach &quot;how to use frameworks.&quot; It disassembles their internal mechanisms so that you understand why they are designed this way, where their performance bottlenecks lie, and when you should bypass the abstraction and operate at a lower level.</p><h2 id="core-topics" tabindex="-1">Core Topics <a class="header-anchor" href="#core-topics" aria-label="Permalink to &quot;Core Topics&quot;">​</a></h2><ul><li><strong>Scheduling mechanisms</strong>: React Fiber linked-list structure, time slicing, interruptible rendering, and concurrent mode.</li><li><strong>Reactivity systems</strong>: Vue 3 Proxy dependency collection, Effect scheduling, and implementation differences among ref / reactive / computed.</li><li><strong>State management</strong>: Design evolution of Flux unidirectional flow, Redux middleware, Zustand atomicity, and Recoil derived state.</li><li><strong>Engineering trade-offs</strong>: Runtime vs compile time, fine-grained updates vs virtual DOM diff, single store vs atomic state.</li></ul><h2 id="article-guide" tabindex="-1">Article Guide <a class="header-anchor" href="#article-guide" aria-label="Permalink to &quot;Article Guide&quot;">​</a></h2><ul><li><a href="/en/frameworks/react-fiber">React Fiber Architecture</a> — Fiber node structure, Scheduler, and the Lane priority model.</li><li><a href="/en/frameworks/vue3-reactivity">Vue 3 Reactivity System</a> — The complete chain from Proxy traps to Effect scheduling.</li><li><a href="/en/frameworks/state-management">Modern State Management Evolution</a> — The thread of trade-offs among unidirectional flow, immutability, and atomicity.</li></ul><h2 id="intended-readers" tabindex="-1">Intended Readers <a class="header-anchor" href="#intended-readers" aria-label="Permalink to &quot;Intended Readers&quot;">​</a></h2><ul><li>Intermediate and senior frontend engineers who want to understand framework internals rather than only APIs.</li><li>Frontend architects who need to evaluate the performance boundaries of different frameworks during technical decision-making.</li><li>Framework source-code contributors who need a unified perspective on scheduling, reactivity, and state management.</li></ul>',11)])])}const f=t(n,[["render",o]]);export{h as __pageData,f as default};
